import base64, os

# Decode and write the FULL ScheduleView.tsx file
# All JSX was pre-encoded to base64 to avoid tool parser issues

out_dir = "/Users/yxq/Downloads/opencode project1/schedule/src/components"
os.makedirs(out_dir, exist_ok=True)

full = base64.b64decode("")

with open(os.path.join(out_dir, "ScheduleView.tsx"), "w", encoding="utf-8") as f:
    f.write(full)
print(f"Written {len(full)} chars")